:root {
  /* 1. Official Dayzo Brand Palette (Hues are consistent) */
  --color-primary: #7C3AED;      /* Primary Purple */
  --color-primary-soft: #A78BFA; /* Secondary Purple */
  --color-accent: #C4B5FD;       /* Accent Purple */

  --color-success: #22C55E;
  --color-warning: #F59E0B;
  --color-error: #EF4444;

  /* 2. Light Mode Tokens (Default) */
  --bg-page: #FFFFFF;
  --bg-secondary: #F8FAFC;
  --bg-card: #FFFFFF;
  --text-primary: #0F172A;
  --text-secondary: #64748B;
  --border-color: #E2E8F0;

  /* Shared Functional Token - Shadow */
  --shadow-sm: 0 2px 4px rgba(0,0,0,0.04), 0 1px 2px rgba(0,0,0,0.02);
  --shadow-md: 0 10px 25px -5px rgba(124, 58, 237, 0.1), 0 8px 10px -6px rgba(15, 23, 42, 0.05);
  --shadow-lg: 0 20px 40px -10px rgba(124, 58, 237, 0.15), 0 12px 20px -8px rgba(15, 23, 42, 0.08);
  --shadow-xl: 0 35px 60px -15px rgba(124, 58, 237, 0.2), 0 20px 35px -10px rgba(15, 23, 42, 0.1);
  --shadow-glow: 0 0 30px rgba(124, 58, 237, 0.4);

  /* 3. Typography Rules */
  --font-family-base: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  --font-family-numbers: 'Inter', system-ui, sans-serif;

  /* Radius */
  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --radius-pill: 9999px;

  /* Global Transitions */
  --transition-fast: 0.2s cubic-bezier(0.16, 1, 0.3, 1);
  --transition-normal: 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

/* 4. Dark Mode Tokens */
[data-theme="dark"] {
  --bg-page: #0F172A;
  --bg-secondary: #111827;
  --bg-card: #1E293B;
  --text-primary: #F1F5F9;
  --text-secondary: #94A3B8;
  --border-color: #334155;

  /* Adjust Shadows for Dark Mode to be more subtle but visible */
  --shadow-sm: 0 2px 4px rgba(0,0,0,0.4);
  --shadow-md: 0 10px 25px -5px rgba(0,0,0,0.5), 0 8px 10px -6px rgba(0,0,0,0.4);
  --shadow-lg: 0 20px 40px -10px rgba(124, 58, 237, 0.2), 0 12px 20px -8px rgba(0,0,0,0.6);
  --shadow-xl: 0 35px 60px -15px rgba(124, 58, 237, 0.3), 0 20px 35px -10px rgba(0,0,0,0.8);
  --shadow-glow: 0 0 40px rgba(124, 58, 237, 0.5);
}

/* 5. Auto Theme Support (System Preference) */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]) {
    --bg-page: #0F172A;
    --bg-secondary: #111827;
    --bg-card: #1E293B;
    --text-primary: #F1F5F9;
    --text-secondary: #94A3B8;
    --border-color: #334155;
    --shadow-sm: 0 2px 4px rgba(0,0,0,0.4);
    --shadow-md: 0 10px 25px -5px rgba(0,0,0,0.5), 0 8px 10px -6px rgba(0,0,0,0.4);
    --shadow-lg: 0 20px 40px -10px rgba(124, 58, 237, 0.2), 0 12px 20px -8px rgba(0,0,0,0.6);
    --shadow-xl: 0 35px 60px -15px rgba(124, 58, 237, 0.3), 0 20px 35px -10px rgba(0,0,0,0.8);
    --shadow-glow: 0 0 40px rgba(124, 58, 237, 0.5);
  }
}

/* Dayzo Create Live & Form Interface */

.create-form-container {
  max-width: 640px;
  margin: 64px auto;
  background: var(--bg-card);
  padding: 48px;
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  border: 1px solid var(--border-color);
}

.form-group {
  margin-bottom: 24px;
}

.form-label {
  display: block;
  font-weight: 700;
  margin-bottom: 8px;
  color: var(--text-primary);
  font-size: 0.95rem;
}

.form-input {
  width: 100%;
  padding: 14px 18px;
  font-size: 1rem;
  font-family: inherit;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  outline: none;
  transition: all var(--transition-fast);
  background: var(--bg-secondary);
  color: var(--text-primary);
}

.form-input:focus {
  border-color: var(--color-primary);
  background: var(--bg-card);
  box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.1);
}

.form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}

.form-actions {
  display: flex;
  gap: 16px;
  margin-top: 32px;
}

.result-section {
  margin-top: 48px;
  padding-top: 32px;
  border-top: 1px solid var(--border-color);
  display: none;
}

.result-section.active {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.description-text {
  font-size: 0.95rem;
  color: var(--text-secondary);
  margin-bottom: 32px;
  text-align: center;
}

.generated-url-box {
  width: 100%;
  padding: 16px;
  background: var(--bg-secondary);
  border: 1px dashed var(--border-color);
  border-radius: var(--radius-md);
  word-break: break-all;
  font-family: var(--font-family-numbers);
  font-size: 0.85rem;
  color: var(--color-primary);
  font-weight: 600;
}

.qr-canvas-container {
  padding: 16px;
  background: #FFF;
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  display: flex;
  justify-content: center;
}

@media (max-width: 640px) {
  .create-form-container { padding: 24px; margin: 32px 16px; }
  .form-grid { grid-template-columns: 1fr; }
}

/* Dayzo TV Mode Styles */
/* Inherits core immersion from base, refined for display-only contexts */

body.mode-tv {
  background: #000000;
  color: #FFFFFF;
  margin: 0;
  padding: 0;
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: var(--font-family-base);
}

.tv-background {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: -1;
  background-size: cover;
  background-position: center;
}

.tv-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 0;
  background: radial-gradient(circle at center, rgba(0,0,0,0.1) 0%, rgba(0,0,0,0.9) 100%);
}

.tv-container {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  height: 100%;
  padding: 4vh;
  text-align: center;
}

.tv-title {
  font-size: clamp(3rem, 12vh, 10rem);
  font-weight: 900;
  margin-bottom: 2vh;
  text-shadow: 0 10px 40px rgba(0,0,0,0.8);
  letter-spacing: -0.04em;
  color: #FFFFFF;
}

.tv-countdown-wrap {
  display: flex;
  gap: 4vw;
  justify-content: center;
  align-items: center;
  margin-top: 2vh;
}

.tv-segment {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.tv-num {
  font-size: clamp(5rem, 25vh, 20rem);
  font-weight: 900;
  font-variant-numeric: tabular-nums;
  line-height: .8;
  text-shadow: 0 20px 60px rgba(0,0,0,0.6);
  font-family: var(--font-family-numbers);
  color: #FFFFFF;
}

.tv-label {
  font-size: clamp(1rem, 3vh, 3.5rem);
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.25em;
  color: rgba(255, 255, 255, 0.4);
  margin-top: 2vh;
}

/* TV specific final countdown overrides */
.tv-final-10 .tv-final-num {
  font-size: 50vh;
  font-weight: 900;
  color: var(--color-primary);
  text-shadow: 0 0 100px rgba(124, 58, 237, 0.8);
}

/* Subtle Branding */
.tv-branding {
  position: absolute;
  top: 4vh;
  left: 4vh;
  font-size: 1.5rem;
  font-weight: 900;
  opacity: 0.4;
  letter-spacing: -0.05em;
  color: #FFFFFF;
}

/* TV QR Box - Highly visible at the bottom */
.tv-qr-region {
  position: absolute;
  bottom: 4vh;
  right: 4vh;
  display: flex;
  align-items: center;
  gap: 24px;
  background: rgba(255, 255, 255, 0.95);
  padding: 16px 32px;
  border-radius: var(--radius-lg);
  box-shadow: 0 30px 60px rgba(0,0,0,0.5);
  color: #000;
}

.tv-qr-text {
  font-size: 1.25rem;
  font-weight: 900;
  line-height: 1.2;
}

#qrcode-canvas {
  width: 100px !important;
  height: 100px !important;
}

@media (max-width: 1024px) {
  .tv-num { font-size: 15vh; }
  .tv-title { font-size: 6vh; }
}

/* Dayzo Homepage Specific Styles */

.hero-section {
  text-align: center;
  padding: 120px 0 80px;
}

.hero-title {
  font-size: clamp(2.5rem, 8vw, 4.5rem);
  font-weight: 900;
  line-height: 1.1;
  margin-bottom: 24px;
  letter-spacing: -0.05em;
  color: var(--text-primary);
}

.local-clock {
  font-family: var(--font-family-numbers);
  font-variant-numeric: tabular-nums;
  font-size: clamp(4rem, 15vw, 10rem);
  font-weight: 900;
  color: var(--color-primary);
  margin-bottom: 48px;
  letter-spacing: -0.04em;
  text-shadow: 0 0 40px rgba(124, 58, 237, 0.3);
  transition: all 0.3s ease;
}

.clock-ampm {
  font-size: 0.3em;
  vertical-align: middle;
  opacity: 0.6;
  text-transform: uppercase;
  margin: 0 10px;
}

.search-container {
  max-width: 640px;
  margin: 32px auto;
  position: relative;
}

.search-input {
  width: 100%;
  padding: 18px 28px;
  font-size: 1.125rem;
  border: 1px solid var(--border-color);
  background-color: var(--bg-card);
  color: var(--text-primary);
  border-radius: var(--radius-pill);
  outline: none;
  transition: all var(--transition-normal);
  box-shadow: var(--shadow-md);
}

.search-input:focus {
  border-color: var(--color-primary);
  background-color: var(--bg-card);
  box-shadow: 0 0 0 4px rgba(124, 58, 237, 0.2), var(--shadow-glow);
  transform: translateY(-2px);
}

/* Base Section Styling */
.section {
  padding: 48px 0;
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.section-title {
  font-size: 1.75rem;
  font-weight: 700;
  color: var(--text-primary);
}

/* Event Cards Grid */
.events-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 24px;
}

.section-desc {
  max-width: 700px;
  margin: 12px 0 32px;
  font-size: 1.125rem;
  color: var(--text-secondary);
  line-height: 1.6;
}

.event-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 32px 24px;
  transition: all var(--transition-normal);
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow-md);
  text-align: center;
}

.event-card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-xl);
  border-color: var(--color-primary);
}

.card-title {
  font-size: 1.25rem;
  font-weight: 700;
  margin-bottom: 8px;
  color: var(--text-primary);
}

.card-date {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--text-secondary);
  margin-bottom: 20px;
}

.card-countdown {
  font-size: 1.75rem;
  font-weight: 800;
  color: var(--color-primary);
  margin-bottom: 20px;
  font-variant-numeric: tabular-nums;
  font-family: var(--font-family-numbers);
}

/* Create Banner */
.create-banner {
  background: linear-gradient(135deg, var(--color-primary), #4F46E5);
  color: #fff;
  border-radius: 40px;
  padding: 80px 40px;
