}

@media (max-width: 640px) {
  .countdown-hero { gap: 8px; margin: 32px 0; }
  .countdown-segment { min-width: 60px; }
  .countdown-value { font-size: clamp(2.5rem, 12vw, 4rem); }
  .countdown-label { font-size: 0.65rem; letter-spacing: 0.1em; }
  .content-block { padding: 20px; }
  .create-cta-card { padding: 32px 20px; border-radius: 20px; }
  .create-cta-card h2 { font-size: 1.5rem; }
  .hero-actions { flex-direction: column; align-items: stretch; padding: 0 16px; gap: 12px; }
  .hero-actions .btn { margin: 0 !important; width: 100%; }
