/* Dayzo Live & TV Shared Aesthetic Styles */

body.mode-live, body.mode-tv {
  background: #000000;
  color: #FFFFFF;
  margin: 0;
  padding: 0;
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: var(--font-family-base);
}

.live-background {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: -1;
  background-size: cover;
  background-position: center;
  transition: opacity 1s ease-in-out;
}

.live-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 0;
  background: radial-gradient(circle at center, rgba(0,0,0,0.3) 0%, rgba(0,0,0,0.85) 100%);
  backdrop-filter: blur(2px);
}

.live-container {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 32px;
}

.live-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.live-brand {
  font-weight: 900;
  font-size: 2rem;
  color: #FFFFFF;
  letter-spacing: -0.05em;
  text-shadow: 0 4px 12px rgba(0,0,0,0.5);
}

.live-brand span {
  color: var(--color-primary);
}

/* Central Countdown Display */
.live-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
}

.live-title {
  font-size: clamp(2rem, 8vh, 6rem);
  font-weight: 800;
  margin-bottom: 32px;
  text-shadow: 0 4px 24px rgba(0,0,0,0.8);
  letter-spacing: -0.03em;
}

.live-countdown-wrap {
  display: flex;
  gap: 32px;
  justify-content: center;
  align-items: center;
}

.live-segment {
  display: flex;
  flex-direction: column;
  align-items: center;
  min-width: 120px;
}

.live-num {
  font-size: clamp(4rem, 15vh, 12rem);
  font-weight: 900;
  font-variant-numeric: tabular-nums;
  line-height: .9;
  text-shadow: 0 10px 40px rgba(0,0,0,0.5);
  font-family: var(--font-family-numbers);
}

.live-label {
  font-size: clamp(0.875rem, 2vh, 1.5rem);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.2em;
  color: rgba(255, 255, 255, 0.6);
  margin-top: 12px;
}

/* The Final Countdown - High Intensity */
.live-final-10 .live-final-num {
  font-size: clamp(10rem, 40vh, 25rem);
  font-weight: 900;
  color: var(--color-primary);
  text-shadow: 0 0 60px rgba(124, 58, 237, 0.6);
  animation: pulse-zoom 1s infinite cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes pulse-zoom {
  0% { transform: scale(0.95); opacity: 0.9; }
  50% { transform: scale(1.05); opacity: 1; }
  100% { transform: scale(0.95); opacity: 0.9; }
}

.live-finished-text {
  font-size: clamp(3rem, 10vh, 8rem);
  font-weight: 900;
  text-transform: uppercase;
  color: #FFFFFF;
  text-shadow: 0 0 40px var(--color-primary);
  animation: shine 3s infinite ease-in-out;
}

@keyframes shine {
  0%, 100% { opacity: 0.8; transform: translateY(0); }
  50% { opacity: 1; transform: translateY(-10px); }
}

.live-footer {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  padding: 16px 0;
}

.live-qr-box {
  background: rgba(255, 255, 255, 1);
  padding: 12px 24px;
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  gap: 16px;
  box-shadow: 0 20px 40px rgba(0,0,0,0.4);
  color: #000;
}

.live-qr-label {
  font-size: 0.85rem;
  font-weight: 800;
  line-height: 1.2;
}

.live-actions .btn {
  background: rgba(255, 255, 255, 0.1);
  color: #fff;
  border: 1px solid rgba(255, 255, 255, 0.2);
  backdrop-filter: blur(10px);
}

.live-actions .btn:hover {
  background: var(--color-primary);
  border-color: var(--color-primary);
}

@media (max-width: 768px) {
  .live-countdown-wrap { gap: 12px; }
  .live-segment { min-width: 60px; }
  .live-num { font-size: 3.5rem; }
  .live-header { flex-direction: column; gap: 8px; }
  .live-footer { flex-direction: column; align-items: center; gap: 16px; width: 100%; }
}

/* Auto TV Mode for Landscape Mobile */
body.tv-mode .live-header,
body.tv-mode .live-footer,
body.tv-mode .personal-content-box {
  display: none !important;
}

body.tv-mode .live-container {
  padding: 0;
  justify-content: center;
}

body.tv-mode .live-title {
  font-size: 10vh;
  margin-bottom: 2vh;
}

body.tv-mode .live-num {
  font-size: 40vh;
}

body.tv-mode .live-label {
  font-size: 5vh;
}

/* Personal Content Styles */
.personal-content-box {
  margin-top: 40px;
  max-width: 800px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(12px);
  padding: 40px;
  border-radius: 32px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 0 32px 64px rgba(0, 0, 0, 0.4);
  animation: fade-in-up 1s ease-out;
}

@keyframes fade-in-up {
  from { opacity: 0; transform: translateY(40px); }
  to { opacity: 1; transform: translateY(0); }
}

.personal-name {
  font-size: clamp(2rem, 5vh, 4rem);
  font-weight: 800;
  margin: 0;
  color: #fff;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
}

.personal-photo {
  width: 180px;
  height: 180px;
  border-radius: 50%;
  overflow: hidden;
  border: 4px solid var(--color-primary);
  box-shadow: 0 0 40px rgba(124, 58, 237, 0.4);
}

.personal-photo img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.personal-message {
  font-size: clamp(1.1rem, 2vh, 1.5rem);
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.9);
  margin: 0;
  font-weight: 500;
  white-space: pre-wrap;
}

/* Dayzo Embed Widget Styles */

body.mode-embed {
  background: transparent;
  color: var(--text-primary);
  margin: 0;
  padding: 0;
  height: 100vh;
  width: 100vw;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  font-family: var(--font-family-base);
}

.embed-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 16px;
  background-color: var(--bg-card);
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
  text-align: center;
  position: relative;
  overflow: hidden;
  transition: background-color var(--transition-normal);
}

.embed-content {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  flex: 1;
  justify-content: center;
  align-items: center;
}

.embed-title {
  font-size: 1.125rem;
  font-weight: 800;
  margin-bottom: 12px;
  color: var(--text-primary);
  line-height: 1.2;
  letter-spacing: -0.02em;
}

.embed-countdown-wrap {
  display: flex;
  gap: 8px;
  justify-content: center;
}

.embed-segment {
  display: flex;
  flex-direction: column;
  align-items: center;
  background: var(--bg-secondary);
  padding: 8px;
  border-radius: var(--radius-sm);
  min-width: 45px;
  border: 1px solid var(--border-color);
}

.embed-num {
  font-size: 1.35rem;
  font-weight: 800;
  font-variant-numeric: tabular-nums;
  color: var(--color-primary);
  line-height: 1;
  font-family: var(--font-family-numbers);
}

.embed-label {
  font-size: 0.6rem;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--text-secondary);
  margin-top: 4px;
}

.embed-footer {
  position: relative;
  z-index: 1;
  margin-top: auto;
  padding-top: 8px;
}

.embed-brand {
  font-size: 0.75rem;
  font-weight: 700;
  color: var(--text-secondary);
  text-decoration: none;
}

.embed-brand span {
  color: var(--color-primary);
}

/* Auto-hiding based on extremely small widths */
@media (max-width: 250px) {
  .embed-segment { min-width: 35px; padding: 4px; }
  .embed-num { font-size: 1.1rem; }
  .embed-label { display: none; }
  .embed-title { font-size: 0.9rem; }
}

/* Finished state */
.embed-finished {
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--color-primary);
  text-transform: uppercase;
}

/* RTL rules applied when HTML dir="rtl" */

html[dir="rtl"] {
  direction: rtl;
}

html[dir="rtl"] body {
  /* Using consistent Arabic font fallbacks */
  font-family: 'Inter', 'Tajawal', 'Cairo', system-ui, sans-serif;
}

html[dir="rtl"] .enriched-content {
  text-align: right;
}

html[dir="rtl"] .content-block .section-title {
  flex-direction: row-reverse;
  justify-content: flex-end;
}

html[dir="rtl"] .share-row {
  flex-direction: row-reverse;
}

/* Flip specific directional icons if used */
html[dir="rtl"] .icon-forward {
  transform: scaleX(-1);
}
html[dir="rtl"] .live-header, 
html[dir="rtl"] .live-footer {
  flex-direction: row-reverse;
}

html[dir="rtl"] .live-qr-box {
  flex-direction: row; /* Keep image and text side-by-side naturally */
}

html[dir="rtl"] .tv-qr-region {
  right: auto;
  left: 4vh;
  flex-direction: row-reverse;
}

html[dir="rtl"] .related-countdowns,
html[dir="rtl"] .create-cta-card {
  text-align: center; /* Always centered for these specific blocks */
}

html[dir="rtl"] .create-cta-card h2 {
  letter-spacing: normal;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  color-scheme: light dark;
}

body {
  font-family: var(--font-family-base);
  background-color: var(--bg-page);
  color: var(--text-primary);
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  transition: background-color var(--transition-normal), color var(--transition-normal);
}

/* Minimalist Container */
.container {
  max-width: 1240px;
  margin: 0 auto;
  padding: 0 24px;
}

@media (max-width: 640px) {
  .container {
    padding: 0 16px;
  }
}

/* Display Modes (Live / TV) overrides */
body.mode-display {
  background-color: #0A0A0A; /* Deep immersive black for TV/Live regardless of theme */
  color: #FFFFFF;
  overflow: hidden;
}

/* Typography Hierarchy */
h1, h2, h3, h4, h5, h6 {
  color: var(--text-primary);
  font-weight: 700;
  letter-spacing: -0.02em;
}

h1 { font-size: 2.5rem; margin-bottom: 1.5rem; }
h2 { font-size: 1.75rem; margin-bottom: 1rem; }

a {
  color: var(--color-primary);
  text-decoration: none;
  transition: color var(--transition-fast);
}
a:hover {
  color: var(--color-primary-soft);
}

/* Unified Brand Header */
.brand-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  position: sticky;
  top: 0;
  z-index: 1000;
  background-color: rgba(var(--bg-page-rgb, 255, 255, 255), 0.8);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border-color);
  width: 100%;
}

[data-theme="dark"] .brand-header {
  background-color: rgba(15, 23, 42, 0.8);
